import {
  Type,
  Lightbulb,
  ImageIcon,
  Play,
} from "lucide-react";

/* ------------------------------------------------------------------ */
/*  Node Swatch                                                        */
/* ------------------------------------------------------------------ */

const nodeTypes = [
  {
    key: "text" as const,
    label: "Text Node",
    icon: Type,
    description: "Nodo di testo editabile per annotazioni e note",
  },
  {
    key: "conceptCard" as const,
    label: "Concept Card",
    icon: Lightbulb,
    description: "Card strutturata con titolo, descrizione e tag",
  },
  {
    key: "imageUpload" as const,
    label: "Image Node",
    icon: ImageIcon,
    description: "Upload e visualizzazione immagini",
  },
  {
    key: "run" as const,
    label: "Run Node",
    icon: Play,
    description: "Esecuzione AI con prompt e output",
  },
];

function NodeSwatch({
  nodeKey,
  label,
  icon: Icon,
  description,
}: {
  nodeKey: keyof typeof NODE_COLORS;
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  description: string;
}) {
  const color = NODE_COLORS[nodeKey];

  return (
    <div
      className="overflow-hidden rounded-2xl border"
      style={{
        borderColor: "var(--node-border)",
        backgroundColor: "var(--node-bg)",
        borderLeftWidth: 4,
        borderLeftColor: color,
      }}
    >
      {/* Header */}
      <div
        className="flex items-center gap-2 px-4 py-2.5"
        style={{ background: tintBg(color, 0.15) }}
      >
        <div
          className="flex h-6 w-6 items-center justify-center rounded-md"
          style={{ background: tintBg(color, 0.25) }}
        >
          <Icon className="size-3.5" style={{ color }} />
        </div>
        <span className="text-sm font-medium text-foreground">{label}</span>
      </div>

      {/* Body */}
      <div className="space-y-2 px-4 py-3">
        <p className="text-xs text-muted-foreground">{description}</p>
        <div className="flex items-center gap-2">
          <div
            className="h-4 w-4 rounded-full"
            style={{ backgroundColor: color }}
          />
          <span className="font-mono text-[10px] text-muted-foreground">
            {color}
          </span>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Page                                                               */
/* ------------------------------------------------------------------ */

