  return (
    <div className="w-full max-w-4xl space-y-10 bg-background p-8 text-foreground">
      <div>
        <h1 className="text-2xl font-bold">Node Colors</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          Ogni tipo di nodo sulla canvas ha un colore identificativo usato
          per il bordo sinistro, l&apos;header tintato e il glow di selezione.
        </p>
      </div>

      {/* Swatches */}
      <div className="grid gap-4 sm:grid-cols-2">
        {nodeTypes.map((n) => (
          <NodeSwatch
            key={n.key}
            nodeKey={n.key}
            label={n.label}
            icon={n.icon}
            description={n.description}
